const hoje = new Date();
const amanha = new Date(hoje.getTime() + 24 * 60 * 60 * 1000);
const diaSemana = amanha.getDay();

const agenda = {
  0: null,
  1: { formato: '📊 Carrossel', hora: '7h30', pilar: 'Educação', checklist: '□ Slides no Canva (5–8 slides)
□ Slide 1: gancho forte
□ Último slide: CTA (eBook ou Grupo WA)
□ Legenda escrita
□ Hashtags (máx 10)' },
  2: { formato: '🎬 Reels', hora: '19h00', pilar: 'Urgência', checklist: '□ Roteiro gravado / filmado
□ Editado no CapCut (30–60s)
□ Legendas automáticas
□ Thumbnail definida
□ Legenda + CTA escrita' },
  3: { formato: '📲 Stories', hora: '12h00', pilar: 'Engajamento', checklist: '□ 3–5 stories planejados
□ Enquete ou quiz criado
□ Link do eBook/WA no último story' },
  4: { formato: '📊 Carrossel', hora: '18h00', pilar: 'Solução', checklist: '□ Slides no Canva (5–8 slides)
□ Slide 1: gancho forte
□ Último slide: CTA
□ Legenda escrita' },
  5: { formato: '🎬 Reels', hora: '7h30', pilar: 'Autoridade', checklist: '□ Roteiro gravado / filmado
□ Editado (30–60s)
□ Legendas automáticas
□ Legenda + CTA escrita' },
  6: { formato: '📷 Feed Foto', hora: '10h00', pilar: 'Autoridade', checklist: '□ Foto selecionada ou criada
□ Arte finalizada (1080x1080)
□ Legenda com quote
□ CTA no final da legenda' }
};

const postagem = agenda[diaSemana];
const nomesDia = ['Domingo','Segunda','Terça','Quarta','Quinta','Sexta','Sábado'];
const nomeAmanha = nomesDia[diaSemana];
const dataStr = amanha.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });

if (!postagem) {
  return [{ json: { mensagem: `📲 AMANHÃ É DOMINGO (${dataStr})

Nenhuma postagem obrigatória.
✅ Opcional: Stories de bastidores às 16h.

Descanse e prepare a semana! 💪` } }];
}

const msg = `⏰ AMANHÃ: ${nomeAmanha} ${dataStr}

${postagem.formato} às ${postagem.hora}
Pilar: ${postagem.pilar}

✅ Checklist:
${postagem.checklist}

💡 Agendar no Meta Business Suite para ${postagem.hora}.`;

return [{ json: { mensagem: msg } }];
